func (a *Adapter) CreateMeter(ctx context.Context, input meterpkg.CreateMeterInput) (meterpkg.Meter, error) {
	return transaction.Run(ctx, a, func(ctx context.Context) (meterpkg.Meter, error) {
		return entutils.TransactingRepo(ctx, a, func(ctx context.Context, repo *Adapter) (meterpkg.Meter, error) {
			entity, err := repo.db.Meter.Create().
				SetNamespace(input.Namespace).
				SetKey(input.Key).
				SetAggregation(input.Aggregation).
				Save(ctx)
			if err != nil {
				if db.IsConstraintError(err) {
					return meterpkg.Meter{}, models.NewGenericConflictError(fmt.Errorf("meter already exists"))
				}
				return meterpkg.Meter{}, fmt.Errorf("failed to create meter: %w", err)
			}
			return MapFromEntityFactory(entity)
		})
	})
}

func (h *handler) GetMeter() GetMeterHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, idOrSlug string) (GetMeterRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil { return GetMeterRequest{}, err }
			return GetMeterRequest{namespace: ns, idOrSlug: idOrSlug}, nil
		},
		func(ctx context.Context, request GetMeterRequest) (GetMeterResponse, error) {
			m, err := h.meterService.GetMeterByIDOrSlug(ctx, meter.GetMeterInput{Namespace: request.namespace, IDOrSlug: request.idOrSlug})
			if err != nil { return GetMeterResponse{}, err }
			return ToAPIMeter(m), nil
		},
		commonhttp.JSONResponseEncoderWithStatus[GetMeterResponse](http.StatusOK),
		httptransport.AppendOptions(h.options, httptransport.WithOperationName("getMeter"))...,
	)
}

func (s *ManageService) DeleteMeter(ctx context.Context, input meter.DeleteMeterInput) error {
	getMeter, err := s.GetMeterByIDOrSlug(ctx, meter.GetMeterInput{Namespace: input.Namespace, IDOrSlug: input.IDOrSlug})
	if err != nil { return err }
	if getMeter.DeletedAt != nil { return nil } // idempotent
	hasFeatures, err := s.adapter.HasActiveFeatureForMeter(ctx, input.Namespace, getMeter.ID)
	if err != nil { return fmt.Errorf("check features: %w", err) }
	if hasFeatures { return models.NewGenericConflictError(fmt.Errorf("meter has active features")) }
	if err = s.adapter.DeleteMeter(ctx, getMeter); err != nil { return err }
	// re-fetch to get DeletedAt populated
	deletedMeter, err := s.GetMeterByIDOrSlug(ctx, meter.GetMeterInput{Namespace: input.Namespace, IDOrSlug: input.IDOrSlug})
	if err != nil { return err }
	if err := s.publisher.Publish(ctx, meter.NewMeterDeleteEvent(ctx, &deletedMeter)); err != nil {
		return fmt.Errorf("publish delete event: %w", err)
	}
	return nil
}
